#### 2. Barramento de Eventos Interno (`/lib/EventBus.js`)
Permite desacoplamento absoluto. Módulos comunicam-se através de eventos tipados.

```javascript
// lib/EventBus.js
const EventEmitter = require('events');
const Logger = require('./Logger');

class EventBus extends EventEmitter {
    constructor() {
        super();
        this.on('error', (err) => {
            Logger.error('Erro não capturado no EventBus:', err.stack);
        });
    }

    emit(event, ...args) {
        Logger.info(`Evento disparado: [${event}]`);
        super.emit(event, ...args);
    }
}

// Singleton para garantir barramento único na aplicação
module.exports = new EventBus();
```

