#### 3. Motor do Banco de Dados com Controle de Concorrência (`/database/DbEngine.js`)
Utiliza um sistema de **Queue (Fila de Promessas/Mutex)** por arquivo de persistência para evitar que gravações assíncronas concorrentes corrompam os arquivos JSON.

```javascript
// database/DbEngine.js
const fs = require('fs').promises;
const path = require('path');
const Logger = require('../lib/Logger');

class DbEngine {
    constructor() {
        this.baseDir = path.join(__dirname, '../storage');
        this.locks = new Map(); // Controle de concorrência por tabela
        this.cache = new Map(); // Cache em memória para leitura ultrarrápida
    }

    async init() {
        await fs.mkdir(this.baseDir, { recursive: true });
        await this._ensureFile('users.json', {});
        await this._ensureFile('clans.json', {});
        Logger.system('Banco de dados JSON inicializado com sucesso.');
    }

    async _ensureFile(filename, defaultData) {
        const filePath = path.join(this.baseDir, filename);
        try {
            await fs.access(filePath);
            const content = await fs.readFile(filePath, 'utf-8');
            this.cache.set(filename, JSON.parse(content));
        } catch {
            await fs.writeFile(filePath, JSON.stringify(defaultData, null, 4));
            this.cache.set(filename, defaultData);
        }
    }

    // Mutex Lock Pattern para evitar race conditions
    async _acquireLock(key) {
        while (this.locks.get(key)) {
            await new Promise(resolve => setTimeout(resolve, 5)); // Aguarda liberação
        }
        this.locks.set(key, true);
    }

    _releaseLock(key) {
        this.locks.set(key, false);
    }

    async read(table) {
        const filename = `${table}.json`;
        if (this.cache.has(filename)) {
            return JSON.parse(JSON.stringify(this.cache.get(filename))); // Deep copy
        }
        await this._acquireLock(table);
        try {
            const filePath = path.join(this.baseDir, filename);
            const data = JSON.parse(await fs.readFile(filePath, 'utf-8'));
            this.cache.set(filename, data);
            return data;
        } finally {
            this._releaseLock(table);
        }
    }

    async write(table, data) {
        const filename = `${table}.json`;
        await this._acquireLock(table);
        try {
            const filePath = path.join(this.baseDir, filename);
            this.cache.set(filename, data); // Atualiza cache
            await fs.writeFile(filePath, JSON.stringify(data, null, 4));
        } finally {
            this._releaseLock(table);
        }
    }

    // Métodos Globais Helpers com Validação Estrita de Input (Anti-Injection)
    async getUser(userId) {
        const safeId = String(userId).replace(/[^a-zA-Z0-9]/g, ''); // Sanitização
        const users = await this.read('users');
        if (!users[safeId]) {
            // Esquema padrão de usuário (RPG + Economia)
            users[safeId] = {
                id: safeId,
                money: 1000,
                bank: 0,
                xp: 0,
                level: 1,
                cooldowns: {},
                inventory: [],
                clan: null,
                permission: 'user' // user, admin, owner
            };
            await this.write('users', users);
        }
        return users[safeId];
    }

    async updateUser(userId, updateFn) {
        const safeId = String(userId).replace(/[^a-zA-Z0-9]/g, '');
        const users = await this.read('users');
        const user = users[safeId] || (await this.getUser(safeId));

        updateFn(user); // Executa mutação controlada de forma síncrona dentro da transação

        users[safeId] = user;
        await this.write('users', users);
        return user;
    }

    async deleteUser(userId) {
        const safeId = String(userId).replace(/[^a-zA-Z0-9]/g, '');
        const users = await this.read('users');
        if (users[safeId]) {
            delete users[safeId];
            await this.write('users', users);
            return true;
        }
        return false;
    }
}

module.exports = new DbEngine();
```

