#### 4. Middlewares de Segurança (`/middlewares/Security.js`)
Previne ataques distribuídos (DoS), spam de comandos e resolve o problema mais crítico de bots de economia: o **Double Spending** (múltiplas requisições paralelas simulando o mesmo estado).

```javascript
// middlewares/Security.js
const Logger = require('../lib/Logger');

class SecurityManager {
    constructor() {
        this.rateLimits = new Map(); // ID -> Timestamp
        this.activeExecutions = new Set(); // IDs com comandos em execução ativa (Anti-Dupe)
    }

    /**
     * Rate Limiting Estrito (Anti-Spam)
     */
    checkRateLimit(userId, limitMs = 1500) {
        const now = Date.now();
        const userLimit = this.rateLimits.get(userId);

        if (userLimit && (now - userLimit) < limitMs) {
            return { allowed: false, retryIn: (limitMs - (now - userLimit)) / 1000 };
        }

        this.rateLimits.set(userId, now);
        return { allowed: true };
    }

    /**
     * Trancamento de Execução de Usuário (Anti-Double Spend / Dupe)
     * Impede que o usuário execute um segundo comando enquanto o primeiro não terminou de processar no DB.
     */
    acquireLock(userId) {
        if (this.activeExecutions.has(userId)) {
            Logger.warn(`Tentativa de exploit de dupla execução detectada para o usuário: ${userId}`);
            return false;
        }
        this.activeExecutions.add(userId);
        return true;
    }

    releaseLock(userId) {
        this.activeExecutions.delete(userId);
    }

    /**
     * Validador de Entradas (Anti-Injection / Anti-NaN Exploits)
     */
    validateAmount(amount) {
        const parsed = parseInt(amount, 10);
        if (isNaN(parsed) || parsed <= 0 || !Number.isInteger(parsed) || parsed > 99999999999) {
            return { valid: false, amount: 0 };
        }
        return { valid: true, amount: parsed };
    }
}

module.exports = new SecurityManager();
```

