#### 5. Registro de Comandos e Hot Reload (`/lib/CommandRegistry.js`)
Gerencia o carregamento dinâmico de comandos da pasta nativa e também de módulos de extensão (plugins) externos sem a necessidade de reiniciar o processo principal.

```javascript
// lib/CommandRegistry.js
const fs = require('fs');
const path = require('path');
const Logger = require('./Logger');

class CommandRegistry {
    constructor() {
        this.commands = new Map();
        this.plugins = new Map();
    }

    async loadAll() {
        this.commands.clear();
        const commandsDir = path.join(__dirname, '../commands');

        if (!fs.existsSync(commandsDir)) {
            fs.mkdirSync(commandsDir);
        }

        const files = fs.readdirSync(commandsDir).filter(f => f.endsWith('.js'));
        for (const file of files) {
            this.loadCommand(path.join(commandsDir, file));
        }

        // Carrega plugins externos dinamicamente se a pasta existir
        const pluginsDir = path.join(__dirname, '../plugins');
        if (fs.existsSync(pluginsDir)) {
            const pluginFiles = fs.readdirSync(pluginsDir).filter(f => f.endsWith('.js'));
            for (const file of pluginFiles) {
                this.loadPlugin(path.join(pluginsDir, file));
            }
        }
        Logger.system(`Carregamento concluído: ${this.commands.size} comandos mapeados.`);
    }

    loadCommand(filePath) {
        try {
            delete require.cache[require.resolve(filePath)]; // Remove cache de require para Hot Reload
            const cmdModule = require(filePath);

            if (cmdModule.commands && Array.isArray(cmdModule.commands)) {
                for (const cmd of cmdModule.commands) {
                    this.commands.set(cmd.name, { ...cmd, file: filePath });
                }
            }
            Logger.info(`Comandos carregados com sucesso do arquivo: ${path.basename(filePath)}`);
        } catch (err) {
            Logger.error(`Erro ao carregar o comando no arquivo ${filePath}:`, err.stack);
        }
    }

    loadPlugin(filePath) {
        try {
            delete require.cache[require.resolve(filePath)];
            const plugin = require(filePath);
            if (plugin.init) plugin.init(this);
            Logger.success(`Plugin carregado externamente: ${path.basename(filePath)}`);
        } catch (err) {
            Logger.error(`Erro ao carregar plugin ${filePath}:`, err.stack);
        }
    }

    // Recarrega todos os arquivos em tempo de execução de forma atômica
    async reload() {
        Logger.warn('Iniciando Hot-Reload de todos os comandos e plugins...');
        await this.loadAll();
    }

    get(name) {
        return this.commands.get(name);
    }
}

module.exports = new CommandRegistry();
```

