#### 6. Módulo de Comandos Administrativos (`/commands/admin.js`)
Controles do núcleo e segurança interna de permissões.

```javascript
// commands/admin.js
const CommandRegistry = require('../lib/CommandRegistry');
const DbEngine = require('../database/DbEngine');

module.exports = {
    commands: [
        {
            name: 'reload',
            description: 'Recarrega os comandos do sistema em tempo de execução (Hot-Reload).',
            permission: 'owner',
            execute: async (context) => {
                await CommandRegistry.reload();
                return { success: true, message: '🔄 Todos os módulos e comandos foram recarregados de forma limpa!' };
            }
        },
        {
            name: 'setperm',
            description: 'Muda permissão de um usuário.',
            permission: 'owner',
            execute: async (context) => {
                const [targetId, permLevel] = context.args;
                if (!targetId || !['user', 'admin', 'owner'].includes(permLevel)) {
                    return { success: false, message: 'Uso correto: setperm <id> <user|admin|owner>' };
                }

                await DbEngine.updateUser(targetId, (user) => {
                    user.permission = permLevel;
                });

                return { success: true, message: `Permissão de ${targetId} atualizada para [${permLevel.toUpperCase()}]` };
            }
        }
    ]
};
```

