#### 7. Módulo de Comandos de Economia (`/commands/economy.js`)
Comandos financeiros. Contém travas para evitar saldo negativo, valores flutuantes fracionários (`0.5`) ou transações inválidas via manipulação de propriedades de objetos JS (*prototype pollution*).

```javascript
// commands/economy.js
const DbEngine = require('../database/DbEngine');
const Security = require('../middlewares/Security');
const EventBus = require('../lib/EventBus');

const WORK_COOLDOWN = 60 * 1000; // 1 minuto de cooldown

module.exports = {
    commands: [
        {
            name: 'work',
            description: 'Trabalhe para ganhar moedas de forma honesta.',
            permission: 'user',
            execute: async (context) => {
                const userId = context.userId;
                const user = await DbEngine.getUser(userId);

                const now = Date.now();
                const lastWork = user.cooldowns.work || 0;

                if (now - lastWork < WORK_COOLDOWN) {
                    const timeLeft = Math.ceil((WORK_COOLDOWN - (now - lastWork)) / 1000);
                    return { success: false, message: `Aguarde mais ${timeLeft}s para trabalhar novamente.` };
                }

                const payout = Math.floor(Math.random() * (500 - 150 + 1)) + 150; // R$150 a R$500

                await DbEngine.updateUser(userId, (usr) => {
                    usr.money += payout;
                    usr.cooldowns.work = now;
                });

                EventBus.emit('economy:work', { userId, payout });

                return { success: true, message: `👷 Você trabalhou arduamente e recebeu **$${payout}**!` };
            }
        },
        {
            name: 'bal',
            description: 'Consulta saldo em carteira e banco.',
            permission: 'user',
            execute: async (context) => {
                const user = await DbEngine.getUser(context.userId);
                return { success: true, message: `💰 **Carteira:** $${user.money} | 🏦 **Banco:** $${user.bank}` };
            }
        },
        {
            name: 'pay',
            description: 'Transfere moedas de forma segura para outro usuário.',
            permission: 'user',
            execute: async (context) => {
                const [targetRaw, amountRaw] = context.args;

                if (!targetRaw || !amountRaw) {
                    return { success: false, message: 'Uso: pay <userId> <quantidade>' };
                }

                const targetId = targetRaw.replace(/[^a-zA-Z0-9]/g, '');
                if (targetId === context.userId) {
                    return { success: false, message: 'Você não pode transferir para si mesmo.' };
                }

                const validation = Security.validateAmount(amountRaw);
                if (!validation.valid) {
                    return { success: false, message: 'Insira um valor numérico válido e acima de zero.' };
                }
                const amount = validation.amount;

                // Transação Segura com Travas Atômicas para os dois usuários
                const sender = await DbEngine.getUser(context.userId);
                if (sender.money < amount) {
                    return { success: false, message: 'Saldo em dinheiro vivo insuficiente.' };
                }

                await DbEngine.updateUser(context.userId, (s) => s.money -= amount);
                await DbEngine.updateUser(targetId, (r) => r.money += amount);

                EventBus.emit('economy:transfer', { sender: context.userId, receiver: targetId, amount });

                return { success: true, message: `💸 Transferência de **$${amount}** para o ID **${targetId}** efetuada!` };
            }
        }
    ]
};
```

