#### 8. Módulo de Comandos do RPG (`/commands/rpg.js`)
Formula de progressão exponencial, inventário de itens empilháveis (stackables) e gerador pseudo-aleatório balanceado de loot baseado em raridade.

```javascript
// commands/rpg.js
const DbEngine = require('../database/DbEngine');

const XP_FORMULA = (level) => Math.floor(100 * Math.pow(level, 1.5));

const LOOT_TABLE = [
    { name: 'Pedra Filosofal', rarity: 'lendário', chance: 0.02 },
    { name: 'Espada de Mithril', rarity: 'épico', chance: 0.08 },
    { name: 'Poção de Mana Gigante', rarity: 'raro', chance: 0.20 },
    { name: 'Madeira Úmida', rarity: 'comum', chance: 0.70 }
];

module.exports = {
    commands: [
        {
            name: 'hunt',
            description: 'Vasculhe a floresta escura em busca de monstros, XP e loot valioso.',
            permission: 'user',
            execute: async (context) => {
                const userId = context.userId;
                const user = await DbEngine.getUser(userId);

                const xpGained = Math.floor(Math.random() * 45) + 15;
                let currentXp = user.xp + xpGained;
                let currentLevel = user.level;
                let leveledUp = false;

                // Algoritmo de Subida de Nível Exponencial
                while (currentXp >= XP_FORMULA(currentLevel)) {
                    currentXp -= XP_FORMULA(currentLevel);
                    currentLevel += 1;
                    leveledUp = true;
                }

                // Cálculo do item sorteado por Roll de Probabilidade
                const roll = Math.random();
                let accumulatedChance = 0;
                let lootedItem = null;

                for (const item of LOOT_TABLE) {
                    accumulatedChance += item.chance;
                    if (roll <= accumulatedChance) {
                        lootedItem = item;
                        break;
                    }
                }

                await DbEngine.updateUser(userId, (usr) => {
                    usr.xp = currentXp;
                    usr.level = currentLevel;

                    if (lootedItem) {
                        // Busca o item no inventário para acumular quantidade
                        const invItem = usr.inventory.find(i => i.name === lootedItem.name);
                        if (invItem) {
                            invItem.qty += 1;
                        } else {
                            usr.inventory.push({ name: lootedItem.name, rarity: lootedItem.rarity, qty: 1 });
                        }
                    }
                });

                let response = `🗡️ Você caçou um Goblin e obteve **${xpGained} XP**.\n`;
                if (lootedItem) {
                    response += `📦 **Drop Encontrado:** [${lootedItem.rarity.toUpperCase()}] ${lootedItem.name}!\n`;
                }
                if (leveledUp) {
                    response += `✨ **LEVEL UP!** Parabéns, você subiu para o nível **${currentLevel}**!\n`;
                }

                return { success: true, message: response };
            }
        },
        {
            name: 'inv',
            description: 'Exibe o inventário do aventureiro.',
            permission: 'user',
            execute: async (context) => {
                const user = await DbEngine.getUser(context.userId);
                if (user.inventory.length === 0) {
                    return { success: true, message: '🎒 Seu inventário está completamente vazio.' };
                }

                const list = user.inventory.map(i => `• x${i.qty} **${i.name}** (${i.rarity.toUpperCase()})`).join('\n');
                return { success: true, message: `🎒 **Seu Inventário:**\n${list}` };
            }
        }
    ]
};
```

