#### 9. Módulo de Clãs Avançado (`/commands/clans.js`)
Sistema de facções com hierarquia de cargos rígida e transações financeiras controladas no cofre do clã.

```javascript
// commands/clans.js
const DbEngine = require('../database/DbEngine');
const Security = require('../middlewares/Security');

module.exports = {
    commands: [
        {
            name: 'clan',
            description: 'Gerenciamento completo do clã. Comandos internos: create, invite, deposit, info',
            permission: 'user',
            execute: async (context) => {
                const [action, arg1, arg2] = context.args;
                const userId = context.userId;

                const user = await DbEngine.getUser(userId);
                const clans = await DbEngine.read('clans');

                // AÇÃO: CRIAR CLÃ
                if (action === 'create') {
                    if (user.clan) return { success: false, message: 'Você já faz parte de um clã.' };
                    if (!arg1) return { success: false, message: 'Defina a TAG do clã (máx. 4 letras).' };

                    const tag = arg1.toUpperCase().replace(/[^A-Z]/g, '').slice(0, 4);
                    if (tag.length < 2) return { success: false, message: 'A TAG do clã deve ter entre 2 a 4 caracteres.' };
                    if (clans[tag]) return { success: false, message: 'Esta TAG já está em uso.' };

                    clans[tag] = {
                        tag,
                        owner: userId,
                        members: [{ id: userId, role: 'LEADER' }],
                        bank: 0
                    };

                    await DbEngine.write('clans', clans);
                    await DbEngine.updateUser(userId, (u) => u.clan = tag);

                    return { success: true, message: `🛡️ Clã **[${tag}]** criado com absoluto sucesso!` };
                }

                // AÇÃO: INFORMAÇÃO DO CLÃ
                if (action === 'info') {
                    const tag = user.clan;
                    if (!tag || !clans[tag]) return { success: false, message: 'Você não está em nenhum clã atualmente.' };

                    const clan = clans[tag];
                    const membersCount = clan.members.length;
                    return {
                        success: true,
                        message: `🛡️ **Clã [${clan.tag}]**\n💰 Cofragem: $${clan.bank}\n👥 Membros: ${membersCount}\n👑 Dono: <@${clan.owner}>`
                    };
                }

                // AÇÃO: DEPÓSITO NO COFRE DO CLÃ (Controle de Concorrência)
                if (action === 'deposit') {
                    const tag = user.clan;
                    if (!tag || !clans[tag]) return { success: false, message: 'Você precisa estar em um clã para realizar depósitos.' };

                    const validation = Security.validateAmount(arg1);
                    if (!validation.valid) return { success: false, message: 'Valor inválido de moedas para depósito.' };
                    const amount = validation.amount;

                    if (user.money < amount) return { success: false, message: 'Saldo vivo insuficiente.' };

                    // Transação atômica síncrona
                    await DbEngine.updateUser(userId, (u) => u.money -= amount);

                    // Modifica o banco do clã com segurança
                    clans[tag].bank += amount;
                    await DbEngine.write('clans', clans);

                    return { success: true, message: `💳 Você depositou **$${amount}** no cofre de segurança de seu clã!` };
                }

                return { success: false, message: 'Uso incorreto. Tente: clan <create|info|deposit>' };
            }
        }
    ]
};
```

