#### 11. Orquestrador do Sistema (`/index.js`)
O ponto de partida da aplicação. Liga os middlewares, inicializa o DB com tratamento global de falhas (*uncaughtException*) de modo que o processo não quebre em decorrência de erros de terceiros.

```javascript
// index.js
const DbEngine = require('./database/DbEngine');
const CommandRegistry = require('./lib/CommandRegistry');
const Logger = require('./lib/Logger');
const Security = require('./middlewares/Security');
const EventBus = require('./lib/EventBus');

// Tratamento de segurança global de erros em tempo de execução
process.on('uncaughtException', (err) => {
    Logger.error('FALHA CRÍTICA DO SISTEMA EVITADA (try/catch global):', err.stack);
});

process.on('unhandledRejection', (reason, promise) => {
    Logger.error('Promessa não tratada rejeitada:', reason);
});

class MasterBot {
    constructor() {
        this.prefix = '/';
        this.ownerId = 'admin123'; // Administrador com permissões máximas
    }

    async boot() {
        Logger.system('Iniciando inicialização do núcleo do sistema...');

        await DbEngine.init();
        await CommandRegistry.loadAll();

        // Escuta os logs e transações emitidos de forma descentralizada pelo EventBus
        EventBus.on('economy:transfer', (data) => {
            Logger.info(`[TRANSAÇÃO FINANCEIRA]: ID ${data.sender} enviou $${data.amount} para ID ${data.receiver}`);
        });

        Logger.success('🚀 Sistema ativo! Digite um comando para testá-lo ou use [CTRL + C] para parar.');
        this.runConsoleInputListener();
    }

    /**
     * Ciclo de Vida do Handler de Execução de Mensagem de Comando
     */
    async handleMessage(userId, message) {
        if (!message.startsWith(this.prefix)) return;

        const args = message.slice(this.prefix.length).trim().split(/ +/);
        const commandName = args.shift().toLowerCase();

        const command = CommandRegistry.get(commandName);
        if (!command) {
            Logger.warn(`Comando digitado não reconhecido: [${commandName}]`);
            return;
        }

        // 1. Segurança: Anti-Spam (Rate Limit)
        const rateCheck = Security.checkRateLimit(userId, 1000);
        if (!rateCheck.allowed) {
            console.log(`\x1b[31m[RATE-LIMIT] Usuário ${userId} bloqueado por spam. Espere ${rateCheck.retryIn}s.\x1b[0m`);
            return;
        }

        // 2. Segurança: Lock de Concorrência (Anti-Dupe)
        if (!Security.acquireLock(userId)) {
            console.log(`\x1b[31m[ANTI-DUPE] Comando anterior de ${userId} ainda em andamento. Execução cancelada.\x1b[0m`);
            return;
        }

        try {
            // 3. Verificação de Permissão do Usuário
            const user = await DbEngine.getUser(userId);
            const userPerm = userId === this.ownerId ? 'owner' : user.permission;

            const permissionsLevel = { user: 1, admin: 2, owner: 3 };
            const requiredLevel = permissionsLevel[command.permission || 'user'];
            const userLevel = permissionsLevel[userPerm];

            if (userLevel < requiredLevel) {
                console.log(`\x1b[31m[PERMISSÃO NEGADA] Permissão insuficiente para executar: ${commandName}\x1b[0m`);
                return;
            }

            // 4. Execução do Comando
            const context = { userId, args, ownerId: this.ownerId };
            const result = await command.execute(context);

            if (result.success) {
                console.log(`\x1b[32m[${commandName.toUpperCase()} SUCESSO] ${result.message}\x1b[0m`);
            } else {
                console.log(`\x1b[33m[${commandName.toUpperCase()} ERRO] ${result.message}\x1b[0m`);
            }

        } catch (error) {
            Logger.error(`Falha no fluxo interno ao executar comando "${commandName}":`, error.stack);
        } finally {
            // Libera o lock de proteção do usuário, permitindo o próximo comando
            Security.releaseLock(userId);
        }
    }

    /**
     * CLI interativo direto no terminal para testes dinâmicos locais
     */
    runConsoleInputListener() {
        const readline = require('readline').createInterface({
            input: process.stdin,
            output: process.stdout
        });

        const promptUser = () => {
            readline.question('Digite comando como [usuarioExemplo]:[mensagem] (Ex: "player1:/hunt"): \n', async (input) => {
                const parts = input.split(':');
                if (parts.length >= 2) {
                    const userId = parts[0].trim();
                    const message = parts.slice(1).join(':').trim();
                    await this.handleMessage(userId, message);
                } else {
                    console.log('Use o formato padrão de entrada: <idUsuario>:<mensagem>');
                }
                promptUser();
            });
        };
        promptUser();
    }
}

// Inicializa o Sistema Completo
const system = new MasterBot();
system.boot();
