### 1. O Motor de Banco de Dados (`/lib/db.js`)
Usamos `fs.promises` com travamento básico para evitar corrupção.

```javascript
const fs = require('fs/promises');
const path = require('path');
const dbPath = path.join(__dirname, '../data.json');

class Database {
    constructor() { this.cache = {}; this.load(); }

    async load() {
        try { const data = await fs.readFile(dbPath, 'utf8'); this.cache = JSON.parse(data); }
        catch { this.cache = { users: {}, clans: {} }; }
    }

    async save() {
        await fs.writeFile(dbPath, JSON.stringify(this.cache, null, 2));
    }

    getUser(id) { return this.cache.users[id] || { balance: 0, xp: 0, clan: null, inventory: [] }; }

    async setUser(id, data) {
        this.cache.users[id] = { ...this.getUser(id), ...data };
        await this.save();
    }
}
module.exports = new Database();
