### 2. Event Bus & Core Engine (`index.js`)
O sistema de carregamento dinâmico permite "Hot Reload".

```javascript
const EventEmitter = require('events');
const fs = require('fs');
const path = require('path');

class BotCore extends EventEmitter {
    constructor() {
        super();
        this.commands = new Map();
        this.loadModules();
    }

    loadModules() {
        const cmdPath = path.join(__dirname, 'commands');
        fs.readdirSync(cmdPath).forEach(file => {
            const cmd = require(`./commands/${file}`);
            this.commands.set(cmd.name, cmd);
        });
    }

    execute(cmdName, user, args) {
        const cmd = this.commands.get(cmdName);
        if (!cmd) return;

        // Middleware: Anti-Spam
        if (this.isSpamming(user.id)) return console.log("Rate Limit Exceeded");

        try {
            cmd.run(user, args, this);
        } catch (e) {
            console.error(`Error in ${cmdName}:`, e);
        }
    }

    isSpamming(id) { /* Lógica de Rate Limit */ return false; }
}

const bot = new BotCore();
module.exports = bot;
```

